    <div class=\"container mt-5\" style=\"max-width: 480px;\">
        <h1 class=\"h3 mb-4\">Connexion au back office</h1>

        {% if error %}
            <div class=\"alert alert-danger\">
                Identifiants invalides.
            </div>
        {% endif %}

        <form method=\"post\">
            <input type=\"hidden\" name=\"_csrf_token\" value=\"{{ csrf_token('authenticate') }}\">
            <div class=\"mb-3\">
                <label class=\"form-label\" for=\"username\">Identifiant</label>
                <input type=\"text\" id=\"username\" name=\"_username\" class=\"form-control\" value=\"{{ last_username }}\" required autofocus>
            </div>
            <div class=\"mb-3\">
                <label class=\"form-label\" for=\"password\">Mot de passe</label>
                <input type=\"password\" id=\"password\" name=\"_password\" class=\"form-control\" required>
            </div>
            <button class=\"btn btn-primary w-100\" type=\"submit\">Se connecter</button>
        </form>
    </div>
{% endblock %}
